el_C = zeros(16, 16, no_els);
el_M = zeros(16, 16, no_els);


%Indices into damping matrix for interface terms
i = loc_df ~= 4;
j = loc_df == 4;

C_up = zeros(12, 4, no_els);
%Loop over Gauss points
for g = 1:no_gauss_pts

	switch g
	%Define matrices that depend on Gauss point
		case 1
			%Terms of C_up matrix
			C_up(1, 1, :) = ((root3 ./ 3 + 1) .^ 2 .* (((nds_1_2 .* (root3 ./ 3 + 1)) ./ 4 - (nds_2_2 .* (root3 ./ 3 - 1)) ./ 4 + (nds_3_2 .* (root3 ./ 3 - 1)) ./ 4 - (nds_4_2 .* (root3 ./ 3 + 1)) ./ 4) .* ((nds_1_3 .* (root3 ./ 3 + 1)) ./ 4 - (nds_2_3 .* (root3 ./ 3 + 1)) ./ 4 + (nds_3_3 .* (root3 ./ 3 - 1)) ./ 4 - (nds_4_3 .* (root3 ./ 3 - 1)) ./ 4) - ((nds_1_2 .* (root3 ./ 3 + 1)) ./ 4 - (nds_2_2 .* (root3 ./ 3 + 1)) ./ 4 + (nds_3_2 .* (root3 ./ 3 - 1)) ./ 4 - (nds_4_2 .* (root3 ./ 3 - 1)) ./ 4) .* ((nds_1_3 .* (root3 ./ 3 + 1)) ./ 4 - (nds_2_3 .* (root3 ./ 3 - 1)) ./ 4 + (nds_3_3 .* (root3 ./ 3 - 1)) ./ 4 - (nds_4_3 .* (root3 ./ 3 + 1)) ./ 4)) .* (abs(root3) .^ 2 ./ (3 .* root3) + 1) .^ 2) ./ 16;
