			C_up(2, 4, :) = ((root3 ./ 3 - 1) .* (root3 ./ 3 + 1) .* (((nds_1_1 .* (root3 ./ 3 + 1)) ./ 4 - (nds_2_1 .* (root3 ./ 3 - 1)) ./ 4 + (nds_3_1 .* (root3 ./ 3 - 1)) ./ 4 - (nds_4_1 .* (root3 ./ 3 + 1)) ./ 4) .* ((nds_1_3 .* (root3 ./ 3 + 1)) ./ 4 - (nds_2_3 .* (root3 ./ 3 + 1)) ./ 4 + (nds_3_3 .* (root3 ./ 3 - 1)) ./ 4 - (nds_4_3 .* (root3 ./ 3 - 1)) ./ 4) - ((nds_1_1 .* (root3 ./ 3 + 1)) ./ 4 - (nds_2_1 .* (root3 ./ 3 + 1)) ./ 4 + (nds_3_1 .* (root3 ./ 3 - 1)) ./ 4 - (nds_4_1 .* (root3 ./ 3 - 1)) ./ 4) .* ((nds_1_3 .* (root3 ./ 3 + 1)) ./ 4 - (nds_2_3 .* (root3 ./ 3 - 1)) ./ 4 + (nds_3_3 .* (root3 ./ 3 - 1)) ./ 4 - (nds_4_3 .* (root3 ./ 3 + 1)) ./ 4)) .* (abs(root3) .^ 2 ./ (3 .* root3) + 1) .^ 2) ./ 16;
			C_up(3, 1, :) = ((root3 ./ 3 + 1) .^ 2 .* (((nds_1_1 .* (root3 ./ 3 + 1)) ./ 4 - (nds_2_1 .* (root3 ./ 3 - 1)) ./ 4 + (nds_3_1 .* (root3 ./ 3 - 1)) ./ 4 - (nds_4_1 .* (root3 ./ 3 + 1)) ./ 4) .* ((nds_1_2 .* (root3 ./ 3 + 1)) ./ 4 - (nds_2_2 .* (root3 ./ 3 + 1)) ./ 4 + (nds_3_2 .* (root3 ./ 3 - 1)) ./ 4 - (nds_4_2 .* (root3 ./ 3 - 1)) ./ 4) - ((nds_1_1 .* (root3 ./ 3 + 1)) ./ 4 - (nds_2_1 .* (root3 ./ 3 + 1)) ./ 4 + (nds_3_1 .* (root3 ./ 3 - 1)) ./ 4 - (nds_4_1 .* (root3 ./ 3 - 1)) ./ 4) .* ((nds_1_2 .* (root3 ./ 3 + 1)) ./ 4 - (nds_2_2 .* (root3 ./ 3 - 1)) ./ 4 + (nds_3_2 .* (root3 ./ 3 - 1)) ./ 4 - (nds_4_2 .* (root3 ./ 3 + 1)) ./ 4)) .* (abs(root3) .^ 2 ./ (3 .* root3) + 1) .^ 2) ./ 16;
